"use client";
import { CalendarDays, Trash2, ChevronRight } from 'lucide-react';
import { IconButton } from '@/components/molecules/SaveModal';

export const HistoryItem = ({ item, onDelete, onGoToDetail }: any) => {
  // 💡 ハイフン(-) または スラッシュ(/) で分割する
  const dateParts = item.date ? item.date.split(/[-/]/) : [];
  // 一番最後の要素（日）を取り、先頭の0を消す（06日 -> 6日）
  const dayDisplay = dateParts.length > 0 ? dateParts[dateParts.length - 1].replace(/^0/, '') : '--';

  return (
    <div className="bg-white rounded-[2rem] p-5 border border-slate-200 shadow-sm flex items-center justify-between hover:border-blue-200 transition-all group">
      <div className="flex items-center gap-4">
        <div className="bg-slate-50 p-3 rounded-2xl text-slate-400 group-hover:text-blue-500 transition-colors">
          <CalendarDays size={20} />
        </div>
        
        <div className="flex flex-col">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1">
            {dayDisplay}日
          </span>
          <h3 className="font-black text-slate-700 text-[17px] leading-tight">
            {item.name || "名前なし"}
          </h3>
        </div>
      </div>

      <div className="flex items-center gap-3">
        <div className="text-right mr-1">
          <span className="text-2xl font-black text-slate-800 tabular-nums leading-none">
            {Number(item.totalHours || 0).toFixed(2)}
          </span>
          <span className="text-[10px] font-black opacity-20 ml-1 uppercase">hrs</span>
        </div>

        <div className="flex items-center gap-1">
          {/* onDelete に item 全体を渡すように修正 */}
          <IconButton onClick={() => onDelete(item)} className="text-slate-200 hover:text-red-500">
            <Trash2 size={18} />
          </IconButton>
          <IconButton onClick={onGoToDetail} className="text-slate-300 hover:text-blue-500">
            <ChevronRight size={22} />
          </IconButton>
        </div>
      </div>
    </div>
  );
};